	public int numberOfSubstringss(String s) {
		/*
		 * both of them are exceed 1mint int a,b,c if all thee are greater then 1 it
		 * count++ two pointer star and end based on start
		 * 
		 */
		int a = 0, b = 0, c = 0, count = 0;
		int start = 0, end = 0;
		while (start <= s.length() - 3) {
			while(end <s.length()) {
				if ((a > 0) & (b > 0) & (c > 0)) {
					count = count + s.length() - end;
					break;
				}
				
				if (s.charAt(end) == 'a') {
					a++;
				} else if (s.charAt(end) == 'b') {
					b++;
				} else if (s.charAt(end) == 'c') {
					c++;
				}

				end++;
			}
			if (s.charAt(start) == 'a' & a != 0) {
				a--;
			} else if (s.charAt(start) == 'b' & b != 0) {
				b--;
			} else if (s.charAt(start) == 'c' & c != 0) {
				c--;
			}
			start++;
			//end++;
		}
		return count;
	}

	
	public int numberOfSubstrings8(String s) {
		/*
		 * Neg: each loop we are searching it so we are using another trick like cutting
		 * the nested forloop that also not going help which can run in 1mints
		 */
		int Count = 0, i = 0;
		String ss = null;
			for (int j = 0; j <= s.length(); j++) {
				ss = s.substring(i, j);
				while(ss.contains("a") && ss.contains("b") && ss.contains("c")) {
					i++;
					ss = s.substring(i, j);
				}
				Count=Count+i;
				
			}
		return Count;
	}
	
	public int numberOfSubstrings(String s) {
		/*
		 * Neg: each loop we are searching it so we are using another trick like cutting
		 * the nested forloop that also not going help which can run in 1mints
		 */
		int Count = 0, i = 0;
		int[] arr = new int[3];
			for (int j = 0; j < s.length(); j++) {
				++arr[s.charAt(j)-'a'];
				while(arr[0]>0 & arr[1]>0 & arr[2]>0) {
				--arr[s.charAt(i)-'a'];
				i++;
				}
				Count=Count+i;
				
			}
		return Count;
	}


	

